    setCart(prev => prev.filter(item => item.id !== id));
  };

  const handleOrderComplete = () => {
    setCart([]);
  };

  const cartCount = cart.reduce((sum, item) => sum + item.quantity, 0);

  return (
    <>
      {showIntro && (
        <IntroOverlay 
           onComplete={() => setShowIntro(false)} 
           coverImage="https://i.postimg.cc/vmfxp5XF/Gemini-Generated-Image-6xc5k56xc5k56xc5-(1).png"
        />
      )}

      <Switch>
        {/* Public Store Routes */}
        <Route exact path="/">
          <Layout cartCount={cartCount} products={products}>
            <StoreFront products={products} siteConfig={siteConfig} onAddToCart={handleAddToCart} />
          </Layout>
        </Route>

        <Route path="/story">
          <Layout cartCount={cartCount} products={products}>
            <OurStory />
          </Layout>
        </Route>

        {/* Clean URL Product Route (Slug or ID) */}
        <Route path="/product/:slug">
          <Layout cartCount={cartCount} products={products}>
            <ProductDetails products={products} onAddToCart={handleAddToCart} />
          </Layout>
        </Route>

        <Route path="/collections/:name">
          <Layout cartCount={cartCount} products={products}>
            <CollectionView products={products} onAddToCart={handleAddToCart} />
          </Layout>
        </Route>

        <Route path="/cart">
          <Layout cartCount={cartCount} products={products}>
            <CartView 
              cart={cart}
              onUpdateQuantity={handleUpdateCartQuantity}
              onRemoveItem={handleRemoveFromCart}
            />
          </Layout>
        </Route>

        <Route path="/orders">
          <Layout cartCount={cartCount} products={products}>
            <OrderLookup />
          </Layout>
        </Route>

        <Route path="/checkout">
          <CheckoutView 
            cart={cart}
            onOrderSuccess={handleOrderComplete}
          />
        </Route>

        <Route path="/payment/callback">
          <PaymentCallback />
        </Route>

        {/* Policy Routes */}
        <Route path="/policies/refund">
          <Layout cartCount={cartCount} products={products}>
            <RefundPolicy />
          </Layout>
        </Route>
        <Route path="/policies/shipping">
          <Layout cartCount={cartCount} products={products}>
            <ShippingPolicy />
          </Layout>
        </Route>
        <Route path="/policies/privacy">
          <Layout cartCount={cartCount} products={products}>
            <PrivacyPolicy />
          </Layout>
        </Route>
        <Route path="/policies/terms">
          <Layout cartCount={cartCount} products={products}>
            <TermsPolicy />
          </Layout>
        </Route>

        {/* Admin Routes */}
        <Route path="/admin/login">
          <AdminLogin onLogin={() => setIsAuthenticated(true)} />
        </Route>

        <Route path="/admin/dashboard">
          {isAuthenticated ? (
            <AdminDashboard 
              products={products}
              siteConfig={siteConfig}
              orders={orders}
              onUpdateProducts={setProducts}
              onUpdateSiteConfig={setSiteConfig}
              onUpdateOrders={setOrders}
              onLogout={() => setIsAuthenticated(false)}
              installPrompt={deferredPrompt}
            />
          ) : (
            <AdminLogin onLogin={() => setIsAuthenticated(true)} />
          )}
        </Route>

        {/* Catch-all Route: Redirect to Home if 404 */}
        <Route path="*">
          <Redirect to="/" />
        </Route>
      </Switch>
    </>
  );
};

export default App;

