const App: React.FC = () => {
  const { pathname } = useLocation();

  // Data State
  const [products, setProducts] = useState<Product[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);

  // PWA Install Prompt State
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  // Initialize showIntro. 
  // If we are landing on the payment callback page (e.g. returning from gateway),
  // we default to FALSE to avoid showing the book cover again.
  const [showIntro, setShowIntro] = useState(() => {
    // Check path for callback. window.location.href ensures we catch it regardless of routing mode initially
    if (window.location.href.includes('payment/callback')) return false;
    return true;
  });

  // Site config
  const [siteConfig, setSiteConfig] = useState<SiteConfig>(() => {
    try {
      const saved = localStorage.getItem('ou_config');
      return saved ? JSON.parse(saved) : { heroImage: '' };
    } catch (e) {
      return { heroImage: '' };
    }
  });

  // Cart State
  const [cart, setCart] = useState<CartItem[]>(() => {
    try {
      const saved = localStorage.getItem('ou_cart');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });

  const [isAuthenticated, setIsAuthenticated] = useState(false);

  // --- FIREBASE SUBSCRIPTIONS ---
  useEffect(() => {
    const unsubscribeProducts = subscribeToProducts((fetchedProducts) => {
      setProducts(fetchedProducts);
    });
    const unsubscribeOrders = subscribeToOrders((fetchedOrders) => {
      setOrders(fetchedOrders);
    });
    return () => {
      unsubscribeProducts();
      unsubscribeOrders();
    };
  }, []);

  // Capture PWA Install Prompt
  useEffect(() => {
    const handler = (e: any) => {
      // Prevent the mini-infobar from appearing on mobile
      e.preventDefault();
      // Stash the event so it can be triggered later.
      setDeferredPrompt(e);
      console.log("PWA install prompt captured in App");
    };

    window.addEventListener('beforeinstallprompt', handler);

    return () => {
      window.removeEventListener('beforeinstallprompt', handler);
    };
  }, []);

  useEffect(() => {
    try {
      localStorage.setItem('ou_config', JSON.stringify(siteConfig));
    } catch (e) {}
  }, [siteConfig]);

  useEffect(() => {
    try {
      localStorage.setItem('ou_cart', JSON.stringify(cart));
    } catch (e) {}
  }, [cart]);

  useEffect(() => {
    window.scrollTo(0, 0);
  }, [pathname]);

  // Cart Handlers
  const handleAddToCart = (product: Product, quantity: number = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item);
      }
      return [...prev, { ...product, quantity: quantity }];
    });
  };

  const handleUpdateCartQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        return { ...item, quantity: Math.max(1, item.quantity + delta) };
      }
      return item;
    }));
  };

  const handleRemoveFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const handleOrderComplete = () => {
    setCart([]);
  };

  const cartCount = cart.reduce((sum, item) => sum + item.quantity, 0);

  return (
    <>
      {showIntro && (
        <IntroOverlay 
           onComplete={() => setShowIntro(false)} 
           coverImage="https://i.postimg.cc/vmfxp5XF/Gemini-Generated-Image-6xc5k56xc5k56xc5-(1).png"
        />
      )}

      <Routes>
        {/* Public Store Routes */}
        <Route path="/" element={
          <Layout cartCount={cartCount} products={products}>
            <StoreFront products={products} siteConfig={siteConfig} onAddToCart={handleAddToCart} />
          </Layout>
        } />

        <Route path="/story" element={
          <Layout cartCount={cartCount} products={products}>
            <OurStory />
          </Layout>
        } />

        {/* Clean URL Product Route (Slug or ID) */}
        <Route path="/product/:slug" element={
          <Layout cartCount={cartCount} products={products}>
            <ProductDetails products={products} onAddToCart={handleAddToCart} />
          </Layout>
        } />

        <Route path="/collections/:name" element={
          <Layout cartCount={cartCount} products={products}>
            <CollectionView products={products} onAddToCart={handleAddToCart} />
          </Layout>
        } />

        <Route path="/cart" element={
          <Layout cartCount={cartCount} products={products}>
            <CartView 
              cart={cart}
              onUpdateQuantity={handleUpdateCartQuantity}
              onRemoveItem={handleRemoveFromCart}
            />
          </Layout>
        } />

        <Route path="/orders" element={
          <Layout cartCount={cartCount} products={products}>
            <OrderLookup />
          </Layout>
        } />

        <Route path="/checkout" element={
          <CheckoutView 
            cart={cart}
            onOrderSuccess={handleOrderComplete}
          />
        } />

        <Route path="/payment/callback" element={
          <PaymentCallback />
        } />

        {/* Policy Routes */}
        <Route path="/policies/refund" element={
          <Layout cartCount={cartCount} products={products}>
            <RefundPolicy />
          </Layout>
        } />
        <Route path="/policies/shipping" element={
          <Layout cartCount={cartCount} products={products}>
            <ShippingPolicy />
          </Layout>
        } />
        <Route path="/policies/privacy" element={
          <Layout cartCount={cartCount} products={products}>
            <PrivacyPolicy />
          </Layout>
        } />
        <Route path="/policies/terms" element={
          <Layout cartCount={cartCount} products={products}>
            <TermsPolicy />
          </Layout>
        } />

        {/* Admin Routes */}
        <Route path="/admin/login" element={
          <AdminLogin onLogin={() => setIsAuthenticated(true)} />
        } />

        <Route path="/admin/dashboard" element={
          isAuthenticated ? (
            <AdminDashboard 
              products={products}
              siteConfig={siteConfig}
              orders={orders}
              onUpdateProducts={setProducts}
              onUpdateSiteConfig={setSiteConfig}
              onUpdateOrders={setOrders}
              onLogout={() => setIsAuthenticated(false)}
              installPrompt={deferredPrompt}
            />
          ) : (
            <AdminLogin onLogin={() => setIsAuthenticated(true)} />
          )
        } />

        {/* Catch-all Route: Redirect to Home if 404 */}
        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Product } from '../../types';
import { Trash2, Edit2, Plus, Upload, X, Loader2, Check, Link as LinkIcon, Database, AlertTriangle, Box } from 'lucide-react';
import { addProductToDb, updateProductInDb, deleteProductFromDb, uploadImage } from '../../firebase';

interface ProductManagerProps {
  products: Product[];
}

export const ProductManager: React.FC<ProductManagerProps> = ({ products }) => {
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [saveStatus, setSaveStatus] = useState<'idle' | 'uploading' | 'saving' | 'saved' | 'error'>('idle');
  const [errorMessage, setErrorMessage] = useState('');
  const [isSeeding, setIsSeeding] = useState(false);
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [deleteConfirmation, setDeleteConfirmation] = useState<string | null>(null);

  // Refs for inputs
  const productFileInputRef = useRef<HTMLInputElement>(null);
  const additionalFileInputRef = useRef<HTMLInputElement>(null);
  const [newAdditionalUrl, setNewAdditionalUrl] = useState('');

  const safeProducts = Array.isArray(products) ? products : [];
  const existingCollections = Array.from(new Set(safeProducts.map(p => p.collection || 'Blankets'))).sort();

  // Form State
  const [formData, setFormData] = useState<Product>({
    id: '',
    name: '',
    price: 0,
    description: '',
    image: '',
    additionalImages: [],
    badge: '',
    material: '',
    care: '',
    collection: 'Blankets',
    size: '',
    stock: 0
  });

  const handleEdit = (product: Product) => {
    setFormData({
        ...product,
        collection: product.collection || 'Blankets',
        additionalImages: product.additionalImages || [],
        size: product.size || '',
        stock: product.stock !== undefined ? product.stock : 0
    });
    setEditingProduct(product);
    setIsEditing(true);
    setSaveStatus('idle');
    setErrorMessage('');
    setNewAdditionalUrl('');
  };

  const handleCreate = () => {
    setFormData({
      id: '',
      name: '',
      price: 0,
      description: '',
      image: '',
      additionalImages: [],
      badge: '',
      material: '',
      care: '',
      collection: 'Blankets',
      size: '',
      stock: 0
    });
    setEditingProduct(null);
    setIsEditing(true);
    setSaveStatus('idle');
    setErrorMessage('');
    setNewAdditionalUrl('');
  };

  const handleDeleteClick = (id: string) => {
    if (deleteConfirmation === id) {
      handleDelete(id);
    } else {
      setDeleteConfirmation(id);
      setTimeout(() => {
        setDeleteConfirmation(prev => prev === id ? null : prev);
      }, 3000);
    }
  };

  const handleDelete = async (id: string) => {
    setDeletingId(id);
    setDeleteConfirmation(null);
    try {
      await deleteProductFromDb(id);
    } catch (error: any) {
      console.error("Delete Error:", error);
      const msg = error.message || "Unknown error";
      alert("Failed to delete product: " + msg);
    } finally {
      setDeletingId(null);
    }
  };

  const handleSeedData = async () => {
    setIsSeeding(true);
    const SEED_DATA = [
      {
        name: 'The Dream Castle',
        price: 185,
        description: 'An intricate illustration of a whimsical palace in the clouds. Woven from the finest cashmere, this piece features subtle turret details and starry accents.',
        image: 'https://i.postimg.cc/9QVBP1b5/Gemini-Generated-Image-s2ybu4s2ybu4s2yb.png',
        material: '100% Grade-A Mongolian Cashmere',
        care: 'Dry clean recommended. Hand wash cold with gentle detergent. Lay flat to dry.',
        collection: 'Blankets',
        size: '120cm x 120cm',
        additionalImages: [],
        stock: 50
      },
      {
        name: 'The Parisian Flight',
        price: 145,
        description: 'A majestic voyage begins. Vintage hot air balloons drifting over Parisian rooftops. A delicate blend of organic cotton and silk, finished with a refined latte border.',
        image: 'https://i.postimg.cc/cCSNXQ23/Gemini-Generated-Image-tit282tit282tit2.png',
        material: '80% Organic Cotton, 20% Mulberry Silk',
        care: 'Machine wash delicate cycle in laundry bag. Tumble dry low.',
        collection: 'Blankets',
        size: '110cm x 110cm',
        additionalImages: [],
        stock: 50
      }
    ];

    try {
      for (const data of SEED_DATA) {
        await addProductToDb(data as any);
      }
      alert("Sample data uploaded successfully! The products should appear shortly.");
    } catch (error: any) {
      console.error("Seed Error:", error);
      alert(`Error uploading data: ${error.message}`);
    } finally {
      setIsSeeding(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaveStatus('saving');
    setErrorMessage('');

    try {
      if (editingProduct && editingProduct.id) {
        const { id, ...data } = formData;
        await updateProductInDb(id, data);
      } else {
        const { id, ...data } = formData;
        await addProductToDb(data);
      }
      setSaveStatus('saved');
      setTimeout(() => {
        setIsEditing(false);
        setSaveStatus('idle');
      }, 1000);
    } catch (error: any) {
      console.error(error);
      setSaveStatus('error');
      setErrorMessage(error.message || "Unknown error");
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, type: 'product' | 'additional') => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) {
        alert("File too large. Please select an image under 5MB.");
        return;
      }
      setSaveStatus('uploading');
      setErrorMessage('');

      try {
        const downloadURL = await uploadImage(file);
        if (type === 'product') {
          setFormData(prev => ({ ...prev, image: downloadURL }));
        } else if (type === 'additional') {
          setFormData(prev => ({ 
            ...prev, 
            additionalImages: [...(prev.additionalImages || []), downloadURL] 
          }));
        }
        setSaveStatus('idle');
      } catch (error: any) {
        console.error("Upload failed details:", error);
        setSaveStatus('error');
        setErrorMessage(error.message || "Upload Failed");
      }
    }
  };

  const addUrlToAdditional = () => {
    if (!newAdditionalUrl) return;
    setFormData(prev => ({
      ...prev,
      additionalImages: [...(prev.additionalImages || []), newAdditionalUrl]
    }));
    setNewAdditionalUrl('');
  };

  const removeAdditionalImage = (index: number) => {
    setFormData(prev => ({
      ...prev,
      additionalImages: prev.additionalImages?.filter((_, i) => i !== index) || []
    }));
  };

  return (
    <>
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
