        >
          <Plus size={14} /> Add Product
        </button>
      </div>

      {isEditing ? (
        <div className="bg-white p-6 md:p-8 border border-brand-latte/20 shadow-sm animate-fade-in max-w-2xl mx-auto rounded-[2px]">
