      let entry = `ORDER #${order.id}\n${itemsList}`;

      if (order.isGift) {
        entry += `\n\n[GIFT MESSAGE]\nTo: ${order.giftTo || ''}\nFrom: ${order.giftFrom || ''}`;
      }

      return entry;
    }).join('\n\n----------------------------------------\n\n');

    try {
      await navigator.clipboard.writeText(textToCopy);
      alert(`${ordersToCopy.length} Order(s) copied to clipboard!`);
